def calculer_moyenne(notes):
    if not notes:  # Vérifie si la liste des notes est vide
        return 0
    return sum(notes) / len(notes)

def filtrer_et_trier_etudiants(etudiants):
    resultats = []
    for nom, notes in etudiants:
        moyenne = calculer_moyenne(notes)
        if moyenne >= 12:  # Filtre les étudiants avec une moyenne supérieure ou égale à 12
            resultats.append((nom, moyenne))
    # Trie les étudiants par leur moyenne en ordre décroissant
    resultats.sort(key=lambda etudiant: etudiant[1], reverse=True)
    return resultats

